import io.micrometer.tracing.Tracer;
import io.micrometer.tracing.Span;
import org.springframework.stereotype.Service;

@Service
public class RazorpayVisaSpanService {
    private final Tracer tracer;
    private final VisaClient visaClient;

    RazorpayVisaSpanService(Tracer t, VisaClient c) { tracer=t; visaClient=c; }

    public ChargeResult charge(String cardType, double amount, String token) {
        Span span = tracer.nextSpan().name("visa.charge");
        try (Tracer.SpanInScope ws = tracer.withSpan(span.start())) {
            span.tag("gateway", "visa");
            span.tag("amount", String.valueOf(amount));
            span.tag("cardType", cardType);

            ChargeResult result = visaClient.charge(token, amount);
            span.tag("responseCode", result.code());
            span.tag("approved", String.valueOf(result.approved()));
            return result;
        } catch (Exception e) {
            span.error(e);  // marks span red in Zipkin, adds exception event
            throw e;
        } finally {
            span.end();     // MANDATORY: always end, even on exception
        }
    }

    interface VisaClient { ChargeResult charge(String token, double amount); }
    record ChargeResult(String code, boolean approved) {}
}

import org.springframework.context.annotation.*;
import org.springframework.web.client.RestTemplate;
import io.micrometer.observation.ObservationRegistry;
import org.springframework.http.client.observation.DefaultClientRequestObservationConvention;

@Configuration
public class TracedRestTemplateConfig {

    @Bean
    public RestTemplate restTemplate(ObservationRegistry observationRegistry) {
        // Micrometer auto-instruments RestTemplate for traces:
        // When this RestTemplate makes a call, it:
        // 1. Creates a child span named 'http.client.requests'
        // 2. Adds B3 headers to the outgoing request:
        //    X-B3-TraceId: <current traceId>
        //    X-B3-SpanId: <new child spanId>
        //    X-B3-Sampled: 1
        // 3. Records duration + HTTP status in the span
        RestTemplate rt = new RestTemplate();
        // Spring Boot auto-configures observation for RestTemplate
        // when ObservationRegistry is in the context
        return rt;
    }

    // AUTOMATIC PROPAGATION:
    // PaymentService (traceId=abc123) calls Visa (RestTemplate):
    //   Outgoing request headers:
    //     X-B3-TraceId: abc123      ← same trace
    //     X-B3-SpanId: newSpan456  ← new child span
    //     X-B3-Sampled: 1
    // Visa service receives headers → creates child span with traceId=abc123
    // Zipkin: both spans appear in the same trace 'abc123'

    // WHY WebClient IS PREFERRED:
    // RestTemplate: blocking I/O, works but not ideal for reactive
    // WebClient: reactive, non-blocking
    //            Spring WebFlux apps use WebClient for automatic trace propagation
    //            Trace context flows through reactor Mono/Flux pipelines
    //            Use WebClient.builder() (Spring auto-configures trace propagation)

    public static void main(String[] a) {
        System.out.println("RestTemplate: B3 headers added automatically");
        System.out.println("WebClient: preferred for reactive, same auto-propagation");
    }
}

import io.micrometer.tracing.Tracer;
import io.micrometer.tracing.Span;
import org.springframework.stereotype.Service;

@Service
public class ZerodhaOrderTraceService {
    private final Tracer tracer;
    ZerodhaOrderTraceService(Tracer t) { tracer=t; }

    public String placeOrder(String symbol, String type, int qty) {
        // Parent span: auto-created by Spring MVC for the @PostMapping
        // Child spans added below:

        boolean valid = validateOrder(symbol, type, qty);
        if (!valid) return "REJECTED:VALIDATION";

        boolean marginOk = checkMargin(symbol, qty);
        if (!marginOk) return "REJECTED:MARGIN";

        return submitToNse(symbol, type, qty);
    }

    boolean validateOrder(String symbol, String type, int qty) {
        Span s = tracer.nextSpan().name("order.validate");
        try (var ws = tracer.withSpan(s.start())) {
            s.tag("symbol", symbol).tag("type", type).tag("qty", String.valueOf(qty));
            Thread.sleep(5);
            s.tag("valid", "true");
            return true;
        } catch (InterruptedException e) {
            Thread.currentThread().interrupt();
            s.error(e);
            return false;
        } finally { s.end(); }
    }

    boolean checkMargin(String symbol, int qty) {
        Span s = tracer.nextSpan().name("margin.check");
        try (var ws = tracer.withSpan(s.start())) {
            s.tag("symbol", symbol).tag("qty", String.valueOf(qty));
            Thread.sleep(10);
            s.tag("marginAvailable", "true");
            return true;
        } catch (InterruptedException e) {
            Thread.currentThread().interrupt();
            s.error(e);
            return false;
        } finally { s.end(); }
    }

    String submitToNse(String symbol, String type, int qty) {
        Span s = tracer.nextSpan().name("nse.submit");
        try (var ws = tracer.withSpan(s.start())) {
            s.tag("exchange", "NSE").tag("symbol", symbol);
            Thread.sleep(20);
            String orderId = "NSE-" + System.currentTimeMillis();
            s.tag("orderId", orderId);
            return orderId;
        } catch (InterruptedException e) {
            Thread.currentThread().interrupt();
            s.error(e);
            return "FAILED";
        } finally { s.end(); }
    }
}

