import io.micrometer.tracing.Tracer;
import io.micrometer.tracing.BaggageField;
import org.springframework.stereotype.Service;

// application.yml:
// management.tracing.baggage.remote-fields: user.id, merchant.id
// management.tracing.baggage.correlation.fields: user.id, merchant.id
// The 'correlation.fields' makes baggage appear in MDC (and thus in logs!)

@Service
public class BaggageContextService {
    private static final BaggageField USER_ID_FIELD =
        BaggageField.create("user.id");

    // Set on request entry (e.g., in a filter after authentication):
    public void setUserId(String userId) {
        USER_ID_FIELD.updateValue(userId);
        // Now propagated in all outgoing HTTP calls
        // and available in all child spans
    }

    public String getUserId() {
        return USER_ID_FIELD.getValue();
    }

    // USE CASE:
    // PaymentFilter: authenticates user, sets USER_ID_FIELD
    // PaymentService: calls FraudService (userId propagated in header)
    // FraudService: reads USER_ID_FIELD — same userId, no explicit passing!
    //
    // Logs: if user.id is in correlation.fields:
    //   19:05:23 [INFO] [traceId=abc123] [user.id=USR-001] PaymentService - Payment started
    //   19:05:23 [INFO] [traceId=abc123] [user.id=USR-001] FraudService - Risk check passed

    public static void main(String[] a) {
        System.out.println("Baggage: propagates key-value pairs across service boundaries");
        System.out.println("correlation.fields: baggage also appears in MDC (logs)");
    }
}

