import io.micrometer.tracing.Tracer;
import io.micrometer.tracing.Span;
import org.springframework.stereotype.*;
import org.springframework.boot.test.context.SpringBootTest;
import org.springframework.beans.factory.annotation.Autowired;
import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.*;

@Service
class RazorpayTracingService {
    private final Tracer tracer;
    RazorpayTracingService(Tracer t) { tracer=t; }

    String processPayment(String gateway, double amount) {
        boolean valid = spanOp("card.validate", Map.of("gateway",gateway), () -> {
            try{Thread.sleep(3);}catch(InterruptedException e){Thread.currentThread().interrupt();}
            return true;
        });
        if (!valid) throw new IllegalStateException("Card invalid");

        String chargeId = spanOp("visa.charge",
            Map.of("gateway",gateway,"amount",String.valueOf(amount)),
            () -> { try{Thread.sleep(50);}catch(InterruptedException e){Thread.currentThread().interrupt();} return "CHG-123"; });

        spanOp("payment.persist", Map.of("chargeId",chargeId),
            () -> { try{Thread.sleep(10);}catch(InterruptedException e){Thread.currentThread().interrupt();} return null; });

        return chargeId;
    }

    <T> T spanOp(String name, java.util.Map<String,String> tags, java.util.concurrent.Callable<T> op) {
        Span s = tracer.nextSpan().name(name);
        try (var ws = tracer.withSpan(s.start())) {
            tags.forEach(s::tag);
            return op.call();
        } catch (Exception e) {
            s.error(e); throw new RuntimeException(e);
        } finally { s.end(); }
    }
}

@SpringBootTest
class RazorpayTracingTest {
    @Autowired RazorpayTracingService svc;
    @Autowired Tracer tracer;
    @Test void payment_processesWithSpans() {
        // Verify no exception thrown (spans created internally):
        assertDoesNotThrow(() -> svc.processPayment("visa", 999.0));
    }
    @Test void tracer_isAvailable() {
        assertNotNull(tracer, "Tracer should be auto-configured");
        // Create a test span to verify tracer works:
        Span s = tracer.nextSpan().name("test.span");
        assertDoesNotThrow(() -> {
            try (var ws = tracer.withSpan(s.start())) {
                s.tag("test", "true");
            } finally { s.end(); }
        });
    }
}

