import io.micrometer.tracing.Tracer;
import io.micrometer.tracing.Span;
import org.springframework.scheduling.annotation.Async;
import org.springframework.stereotype.Service;
import java.util.concurrent.CompletableFuture;

@Service
public class AsyncTracingService {
    private final Tracer tracer;
    AsyncTracingService(Tracer t) { tracer=t; }

    // @Async: Spring runs this in a different thread
    // Thread context (including trace) does NOT automatically transfer
    @Async
    public CompletableFuture<String> sendNotificationAsync(String userId, String message) {
        // Capture the current span BEFORE going async:
        Span parentSpan = tracer.currentSpan();

        return CompletableFuture.supplyAsync(() -> {
            // In the async thread: create a new span linked to parent
            Span asyncSpan = tracer.nextSpan()
                .name("notification.send.async")
                .tag("userId", userId);

            try (Tracer.SpanInScope ws = tracer.withSpan(asyncSpan.start())) {
                // traceId is now propagated in this thread:
                System.out.println("[Async] Sending to " + userId);
                Thread.sleep(50);
                return "SENT";
            } catch (InterruptedException e) {
                Thread.currentThread().interrupt();
                asyncSpan.error(e);
                return "FAILED";
            } finally {
                asyncSpan.end();
            }
        });
    }

    // WITHOUT propagation:
    // Thread 1 (request): traceId=abc123
    // Thread 2 (async): traceId=EMPTY — completely separate, orphaned!
    // Zipkin: async span appears as a separate, disconnected trace
    //
    // WITH propagation (above):
    // Thread 2 creates child span with Thread 1's context
    // Zipkin: async span appears as a child of the request span

    public static void main(String[] a) {
        System.out.println("Async without propagation: orphaned trace (disconnected)");
        System.out.println("Async with propagation: child span in same trace");
    }
}

import io.micrometer.tracing.Tracer;
import io.micrometer.tracing.Span;
import org.springframework.stereotype.*;
import org.springframework.boot.test.context.SpringBootTest;
import org.springframework.beans.factory.annotation.Autowired;
import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.*;

// Simulated Zipkin waterfall:
// POST /api/orders                (230ms total)
//   order.validate    (5ms)  [═]
//   restaurant.check (15ms)  [══]
//   payment.charge  (200ms)  [══════════════════════════] ← bottleneck 87%
//   order.confirm    (10ms)  [═]

@Service
class SwiggyOrderTrace {
    private final Tracer tr;
    SwiggyOrderTrace(Tracer t){tr=t;}

    String placeOrder(String restaurantId, double amount) {
        span("order.validate",    Map.of("restaurantId",restaurantId),5);
        span("restaurant.check",  Map.of("restaurantId",restaurantId),15);
        String payId=spanReturn("payment.charge",Map.of("amount",String.valueOf(amount)),200,"PAY-"+System.currentTimeMillis());
        span("order.confirm",     Map.of("paymentId",payId),10);
        return "ORD-"+System.currentTimeMillis();
    }

    void span(String name, java.util.Map<String,String> tags, long ms) { spanReturn(name,tags,ms,null); }
    <T> T spanReturn(String name, java.util.Map<String,String> tags, long ms, T result) {
        Span s=tr.nextSpan().name(name);
        try(var ws=tr.withSpan(s.start())){
            tags.forEach(s::tag);
            try{Thread.sleep(ms);}catch(InterruptedException e){Thread.currentThread().interrupt();}
            return result;
        }finally{s.end();}
    }
}

@SpringBootTest
class SwiggyOrderTraceTest{
    @Autowired SwiggyOrderTrace svc;
    @Test void order_placesFully(){
        String orderId=svc.placeOrder("REST-001",499.0);
        assertNotNull(orderId); assertTrue(orderId.startsWith("ORD-"));
    }
}

import io.micrometer.tracing.Tracer;
import io.micrometer.tracing.Span;
import org.springframework.stereotype.*;
import org.springframework.boot.test.context.SpringBootTest;
import org.springframework.beans.factory.annotation.Autowired;
import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.*;

@Service
class FailureTracingService {
    private final Tracer tracer;
    FailureTracingService(Tracer t){tracer=t;}

    boolean process(String id, boolean shouldFail) {
        Span s=tracer.nextSpan().name("payment.process");
        try(var ws=tracer.withSpan(s.start())){
            s.tag("paymentId",id);
            if(shouldFail){
                RuntimeException ex=new RuntimeException("Visa declined for "+id);
                s.error(ex);  // marks span RED in Zipkin
                s.tag("result","failure");
                return false;
            }
            s.tag("result","success");
            return true;
        }finally{s.end();}
    }
}

@SpringBootTest
class FailureTracingTest{
    @Autowired FailureTracingService svc;
    @Test void success_noException(){assertTrue(svc.process("P001",false));}
    @Test void failure_recordsError(){assertFalse(svc.process("P002",true));}
}

// Zipkin display:
// SUCCESS span: white/green bar, result=success tag visible
// ERROR span:   RED bar, error.type=RuntimeException, error.message=Visa declined
// Error spans: sortable, filterable — 'show me all failed spans in last 5 min'

import io.micrometer.core.instrument.*;
import io.micrometer.tracing.Tracer;
import io.micrometer.tracing.Span;
import org.springframework.stereotype.*;
import org.springframework.boot.test.context.SpringBootTest;
import org.springframework.beans.factory.annotation.Autowired;
import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.*;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;

@Service
class RazorpayObsTrinity {
    private static final Logger log = LoggerFactory.getLogger(RazorpayObsTrinity.class);
    private final MeterRegistry reg;
    private final Tracer tracer;
    private final Timer payTimer;

    RazorpayObsTrinity(MeterRegistry r, Tracer t) {
        reg=r; tracer=t;
        payTimer=Timer.builder("trinity.payment.duration").publishPercentiles(0.5,0.95,0.99).register(reg);
    }

    String processPayment(String gateway, double amount) {
        // METRICS + TRACING + LOGGING all together:
        return payTimer.record(() -> {
            Span s=tracer.nextSpan().name("payment.full");
            try(var ws=tracer.withSpan(s.start())){
                s.tag("gateway",gateway).tag("amount",String.valueOf(amount));
                // Log: traceId automatically in MDC via %X{traceId}
                log.info("Processing payment gateway={} amount={}", gateway, amount);
                try { Thread.sleep(50); } catch (InterruptedException e) { Thread.currentThread().interrupt(); }
                String result="PAY-"+System.currentTimeMillis();
                reg.counter("trinity.payments.total","status","success","gateway",gateway).increment();
                s.tag("paymentId",result);
                log.info("Payment complete paymentId={}",result);
                return result;
            }finally{s.end();}
        });
    }
}

@SpringBootTest
class RazorpayObsTrinityTest{
    @Autowired RazorpayObsTrinity svc;
    @Autowired MeterRegistry reg;
    @Autowired Tracer tracer;
    @Test void counter_increments(){
        svc.processPayment("visa",999.0);
        Counter c=reg.find("trinity.payments.total").tag("status","success").counter();
        assertNotNull(c); assertTrue(c.count()>=1);
    }
    @Test void timer_records(){
        svc.processPayment("mastercard",499.0);
        Timer t=reg.find("trinity.payment.duration").timer();
        assertNotNull(t); assertTrue(t.count()>=1);
    }
    @Test void tracer_available(){
        assertNotNull(tracer);
        assertDoesNotThrow(()->svc.processPayment("upi",99.0));
    }
}
